import urllib.request
import re

url = "https://github.com/divakarpandey07/AI-Palmistry-pro/actions/runs/30088156247"
req = urllib.request.Request(url, headers={
    "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64)"
})

try:
    with urllib.request.urlopen(req) as resp:
        html = resp.read().decode("utf-8", errors="ignore")
        job_urls = re.findall(r'/divakarpandey07/AI-Palmistry-pro/actions/runs/30088156247/job/\d+', html)
        job_urls = list(dict.fromkeys(job_urls))
        print("Job URLs for 30088156247:", job_urls)
        if job_urls:
            jurl = "https://github.com" + job_urls[0]
            print(f"Fetching job: {jurl}")
            req_j = urllib.request.Request(jurl, headers={
                "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64)"
            })
            with urllib.request.urlopen(req_j) as resp_j:
                jhtml = resp_j.read().decode("utf-8", errors="ignore")
                clean_text = re.sub(r'<[^>]+>', '\n', jhtml)
                lines = [l.strip() for l in clean_text.splitlines() if l.strip()]
                for l in lines:
                    if any(k in l.lower() for k in ["error", "fail", "exit code", "chmod", "gradle"]):
                        print("  ", l[:120])
except Exception as e:
    print(f"Error: {e}")
